// UpsertActions inserts or updates a actions record with domain-specific columns.
func (s *Store) UpsertActions(data json.RawMessage) error {
	obj, err := DecodeJSONObject(data)
	if err != nil {
		return fmt.Errorf("unmarshaling actions: %w", err)
	}

	id := extractObjectID(obj)
	if id == "" {
		return fmt.Errorf("missing id for actions")
	}
	storageID := resourceStorageID("actions", id, obj)

	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()

	if err := s.upsertGenericResourceTx(tx, "actions", storageID, data); err != nil {
		return err
	}
	if err := s.upsertActionsTx(tx, storageID, obj, data); err != nil {
		return err
	}

	return tx.Commit()
}

// upsertAddressbookTx writes the per-resource domain-table portion of a
// addressbook upsert inside an existing transaction. The caller is
// responsible for the generic resources insert (via upsertGenericResourceTx)
// and for committing the tx. Splitting this out lets UpsertBatch dispatch
// domain inserts per item without opening a per-item transaction.
func (s *Store) upsertAddressbookTx(tx *sql.Tx, id string, obj map[string]any, data json.RawMessage) error {
	if _, err := tx.Exec(
		`INSERT INTO "addressbook" ("id", "data", "synced_at", "ccgid", "contacttype", "cuid", "cunum", "emailaddress", "name", "address", "contactgroup", "contactuid", "contactunum", "exchange", "global", "mailboxid", "section", "selectedaddressbook", "unum")
		 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
		 ON CONFLICT("id") DO UPDATE SET "data" = excluded."data", "synced_at" = excluded."synced_at", "ccgid" = excluded."ccgid", "contacttype" = excluded."contacttype", "cuid" = excluded."cuid", "cunum" = excluded."cunum", "emailaddress" = excluded."emailaddress", "name" = excluded."name", "address" = excluded."address", "contactgroup" = excluded."contactgroup", "contactuid" = excluded."contactuid", "contactunum" = excluded."contactunum", "exchange" = excluded."exchange", "global" = excluded."global", "mailboxid" = excluded."mailboxid", "section" = excluded."section", "selectedaddressbook" = excluded."selectedaddressbook", "unum" = excluded."unum"`,
		id,
		string(data),
		time.Now().UTC().Format(time.RFC3339),
		lookupFieldValue(obj, "ccgid"),
		lookupFieldValue(obj, "contacttype"),
		lookupFieldValue(obj, "cuid"),
		lookupFieldValue(obj, "cunum"),
		lookupFieldValue(obj, "emailaddress"),
		lookupFieldValue(obj, "name"),
		lookupFieldValue(obj, "address"),
		lookupFieldValue(obj, "contactgroup"),
		lookupFieldValue(obj, "contactuid"),
		lookupFieldValue(obj, "contactunum"),
		lookupFieldValue(obj, "exchange"),
		lookupFieldValue(obj, "global"),
		lookupFieldValue(obj, "mailboxid"),
		lookupFieldValue(obj, "section"),
		lookupFieldValue(obj, "selectedaddressbook"),
		lookupFieldValue(obj, "unum"),
	); err != nil {
		return fmt.Errorf("insert into addressbook: %w", err)
	}

	return nil
}

