// UpsertAsset inserts or updates a asset record with domain-specific columns.
func (s *Store) UpsertAsset(data json.RawMessage) error {
	obj, err := DecodeJSONObject(data)
	if err != nil {
		return fmt.Errorf("unmarshaling asset: %w", err)
	}

	id := extractObjectID(obj)
	if id == "" {
		return fmt.Errorf("missing id for asset")
	}
	storageID := resourceStorageID("asset", id, obj)

	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()

	if err := s.upsertGenericResourceTx(tx, "asset", storageID, data); err != nil {
		return err
	}
	if err := s.upsertAssetTx(tx, storageID, obj, data); err != nil {
		return err
	}

	return tx.Commit()
}

