// UpsertClientContract inserts or updates a client_contract record with domain-specific columns.
func (s *Store) UpsertClientContract(data json.RawMessage) error {
	obj, err := DecodeJSONObject(data)
	if err != nil {
		return fmt.Errorf("unmarshaling client_contract: %w", err)
	}

	id := extractObjectID(obj)
	if id == "" {
		return fmt.Errorf("missing id for client_contract")
	}
	storageID := resourceStorageID("client-contract", id, obj)

	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()

	if err := s.upsertGenericResourceTx(tx, "client-contract", storageID, data); err != nil {
		return err
	}
	if err := s.upsertClientContractTx(tx, storageID, obj, data); err != nil {
		return err
	}

	return tx.Commit()
}

