// UpsertFieldInfo inserts or updates a field_info record with domain-specific columns.
func (s *Store) UpsertFieldInfo(data json.RawMessage) error {
	obj, err := DecodeJSONObject(data)
	if err != nil {
		return fmt.Errorf("unmarshaling field_info: %w", err)
	}

	id := extractObjectID(obj)
	if id == "" {
		return fmt.Errorf("missing id for field_info")
	}
	storageID := resourceStorageID("field-info", id, obj)

	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()

	if err := s.upsertGenericResourceTx(tx, "field-info", storageID, data); err != nil {
		return err
	}
	if err := s.upsertFieldInfoTx(tx, storageID, obj, data); err != nil {
		return err
	}

	return tx.Commit()
}

