// UpsertOpportunities inserts or updates a opportunities record with domain-specific columns.
func (s *Store) UpsertOpportunities(data json.RawMessage) error {
	obj, err := DecodeJSONObject(data)
	if err != nil {
		return fmt.Errorf("unmarshaling opportunities: %w", err)
	}

	id := extractObjectID(obj)
	if id == "" {
		return fmt.Errorf("missing id for opportunities")
	}
	storageID := resourceStorageID("opportunities", id, obj)

	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()

	if err := s.upsertGenericResourceTx(tx, "opportunities", storageID, data); err != nil {
		return err
	}
	if err := s.upsertOpportunitiesTx(tx, storageID, obj, data); err != nil {
		return err
	}

	return tx.Commit()
}

