// UpsertProjects inserts or updates a projects record with domain-specific columns.
func (s *Store) UpsertProjects(data json.RawMessage) error {
	obj, err := DecodeJSONObject(data)
	if err != nil {
		return fmt.Errorf("unmarshaling projects: %w", err)
	}

	id := extractObjectID(obj)
	if id == "" {
		return fmt.Errorf("missing id for projects")
	}
	storageID := resourceStorageID("projects", id, obj)

	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()

	if err := s.upsertGenericResourceTx(tx, "projects", storageID, data); err != nil {
		return err
	}
	if err := s.upsertProjectsTx(tx, storageID, obj, data); err != nil {
		return err
	}

	return tx.Commit()
}

// upsertPurchaseOrderTx writes the per-resource domain-table portion of a
// purchase_order upsert inside an existing transaction. The caller is
// responsible for the generic resources insert (via upsertGenericResourceTx)
// and for committing the tx. Splitting this out lets UpsertBatch dispatch
// domain inserts per item without opening a per-item transaction.
