// UpsertPurchaseOrder inserts or updates a purchase_order record with domain-specific columns.
func (s *Store) UpsertPurchaseOrder(data json.RawMessage) error {
	obj, err := DecodeJSONObject(data)
	if err != nil {
		return fmt.Errorf("unmarshaling purchase_order: %w", err)
	}

	id := extractObjectID(obj)
	if id == "" {
		return fmt.Errorf("missing id for purchase_order")
	}
	storageID := resourceStorageID("purchase-order", id, obj)

	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()

	if err := s.upsertGenericResourceTx(tx, "purchase-order", storageID, data); err != nil {
		return err
	}
	if err := s.upsertPurchaseOrderTx(tx, storageID, obj, data); err != nil {
		return err
	}

	return tx.Commit()
}

