// UpsertQuotation inserts or updates a quotation record with domain-specific columns.
func (s *Store) UpsertQuotation(data json.RawMessage) error {
	obj, err := DecodeJSONObject(data)
	if err != nil {
		return fmt.Errorf("unmarshaling quotation: %w", err)
	}

	id := extractObjectID(obj)
	if id == "" {
		return fmt.Errorf("missing id for quotation")
	}
	storageID := resourceStorageID("quotation", id, obj)

	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()

	if err := s.upsertGenericResourceTx(tx, "quotation", storageID, data); err != nil {
		return err
	}
	if err := s.upsertQuotationTx(tx, storageID, obj, data); err != nil {
		return err
	}

	return tx.Commit()
}

