// UpsertSalesOrder inserts or updates a sales_order record with domain-specific columns.
func (s *Store) UpsertSalesOrder(data json.RawMessage) error {
	obj, err := DecodeJSONObject(data)
	if err != nil {
		return fmt.Errorf("unmarshaling sales_order: %w", err)
	}

	id := extractObjectID(obj)
	if id == "" {
		return fmt.Errorf("missing id for sales_order")
	}
	storageID := resourceStorageID("sales-order", id, obj)

	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()

	if err := s.upsertGenericResourceTx(tx, "sales-order", storageID, data); err != nil {
		return err
	}
	if err := s.upsertSalesOrderTx(tx, storageID, obj, data); err != nil {
		return err
	}

	return tx.Commit()
}

