// UpsertService inserts or updates a service record with domain-specific columns.
func (s *Store) UpsertService(data json.RawMessage) error {
	obj, err := DecodeJSONObject(data)
	if err != nil {
		return fmt.Errorf("unmarshaling service: %w", err)
	}

	id := extractObjectID(obj)
	if id == "" {
		return fmt.Errorf("missing id for service")
	}
	storageID := resourceStorageID("service", id, obj)

	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()

	if err := s.upsertGenericResourceTx(tx, "service", storageID, data); err != nil {
		return err
	}
	if err := s.upsertServiceTx(tx, storageID, obj, data); err != nil {
		return err
	}

	return tx.Commit()
}

