// UpsertSupplier inserts or updates a supplier record with domain-specific columns.
func (s *Store) UpsertSupplier(data json.RawMessage) error {
	obj, err := DecodeJSONObject(data)
	if err != nil {
		return fmt.Errorf("unmarshaling supplier: %w", err)
	}

	id := extractObjectID(obj)
	if id == "" {
		return fmt.Errorf("missing id for supplier")
	}
	storageID := resourceStorageID("supplier", id, obj)

	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()

	if err := s.upsertGenericResourceTx(tx, "supplier", storageID, data); err != nil {
		return err
	}
	if err := s.upsertSupplierTx(tx, storageID, obj, data); err != nil {
		return err
	}

	return tx.Commit()
}

