// UpsertSupplierContract inserts or updates a supplier_contract record with domain-specific columns.
func (s *Store) UpsertSupplierContract(data json.RawMessage) error {
	obj, err := DecodeJSONObject(data)
	if err != nil {
		return fmt.Errorf("unmarshaling supplier_contract: %w", err)
	}

	id := extractObjectID(obj)
	if id == "" {
		return fmt.Errorf("missing id for supplier_contract")
	}
	storageID := resourceStorageID("supplier-contract", id, obj)

	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()

	if err := s.upsertGenericResourceTx(tx, "supplier-contract", storageID, data); err != nil {
		return err
	}
	if err := s.upsertSupplierContractTx(tx, storageID, obj, data); err != nil {
		return err
	}

	return tx.Commit()
}

