// UpsertTickets inserts or updates a tickets record with domain-specific columns.
func (s *Store) UpsertTickets(data json.RawMessage) error {
	obj, err := DecodeJSONObject(data)
	if err != nil {
		return fmt.Errorf("unmarshaling tickets: %w", err)
	}

	id := extractObjectID(obj)
	if id == "" {
		return fmt.Errorf("missing id for tickets")
	}
	storageID := resourceStorageID("tickets", id, obj)

	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()

	if err := s.upsertGenericResourceTx(tx, "tickets", storageID, data); err != nil {
		return err
	}
	if err := s.upsertTicketsTx(tx, storageID, obj, data); err != nil {
		return err
	}

	return tx.Commit()
}

